mapper.insert:
/** UsptEvlMfcmmDao.insert */
insert into uspt_evl_mfcmm (
	   evl_mfcmm_id
	 , evl_cmit_id
	 , extrc_mfcmm_id
	 , expert_id
	 , enc_password
	 , use_bgnde
	 , use_endde
	 , refresh_token
	 , charmn
	 , atend_sttus_cd
	 , atend_dt
	 , evas_agre_at
	 , evas_resn_cn
	 , creator_id
	 , created_dt
) values (
	   #{evlMfcmmId}
	 , (
	 	select b.evl_cmit_id
	 	  from USPT_EXTRC_MFCMM a					/*추출위원*/
			   inner join USPT_EVL_MFCMM_EXTRC b 	/*평가위원추출*/
					   on a.MFCMM_EXTRC_ID = b.MFCMM_EXTRC_ID
		 where extrc_mfcmm_id = #{extrcMfcmmId}
	   )
	 , #{extrcMfcmmId}
	 , (select expert_id
	      from uspt_extrc_mfcmm
		 where extrc_mfcmm_id = #{extrcMfcmmId}
	   )
	 , #{encPassword}
	 , #{useBgnde}
	 , #{useEndde}
	 , #{refreshToken}
	 , #{charmn}
	 , #{atendSttusCd}
	 , #{atendDt}
	 , #{evasAgreAt}
	 , #{evasResnCn}
	 , #{creatorId}
	 , #{createdDt}
)

mapper.select:
/** UsptEvlMfcmmDao.select */ select uem.evl_mfcmm_id , uem.evl_cmit_id , uem.extrc_mfcmm_id , uem.expert_id , (select expert_nm from uspt_expert where expert_id = uem.expert_id) as evl_mfcmm_nm , uem.enc_password , uem.use_bgnde , uem.use_endde , uem.refresh_token , uem.charmn , uem.atend_sttus_cd , uem.atend_dt , uem.evas_agre_at , uem.evas_resn_cn , (select max(mfcmm_evl_sttus_cd) from uspt_evl_mfcmm_result where evl_mfcmm_id = uem.evl_mfcmm_id) as mfcmm_evl_sttus_cd , uem.creator_id , uem.created_dt , uem.updater_id , uem.updated_dt from uspt_evl_mfcmm uem
and uem.evl_mfcmm_id = #{evlMfcmmId}
and uem.evl_cmit_id = #{evlCmitId}
and uem.extrc_mfcmm_id = #{extrcMfcmmId}

mapper.delete:
/** UsptEvlMfcmmDao.deleteByCmitId */
delete
  from uspt_evl_mfcmm
 where evl_cmit_id = #{evlCmitId}

mapper.update:
/** UsptEvlMfcmmDao.updateCharmn */
update uspt_evl_mfcmm
set
	charmn = ${charmn}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	evl_mfcmm_id = #{evlMfcmmId}

/** UsptEvlMfcmmDao.updateAtendSttus */
update uspt_evl_mfcmm
set
	atend_sttus_cd = #{atendSttusCd}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
	, evas_resn_cn = #{evasResnCn}
where
	evl_mfcmm_id = #{evlMfcmmId}
